import { get, isNil } from 'lodash-es';

import type { Strategies } from './types.js';
import { always0, getColorFromRule, getSubject, incBy1 } from './utils.js';
import type { ColorPalette } from '../types/color-palette.js';
import { ColorRuleProps } from '../types/color-rule.js';
import { getAccessor } from '../utils/getAccessor.js';
import { getValidColor } from '../utils/getValidColor.js';
import { RANGE_MATCHERS, VALUE_MATCHERS } from '../utils/validators.js';

export const strategies: Strategies = {
  histogram: () => {
    return {
      defaultValueAccessor: 'name',
      forbiddenAccessors: /^name$/,
      getName: (series: { name: string }) => series.name,
      getSubject,
      matchers: VALUE_MATCHERS,
      colorPaletteIndex: incBy1,
      getColorFromRule,
    };
  },
  timeseries: () => {
    return {
      defaultValueAccessor: 'name',
      forbiddenAccessors: /^name$/,
      getName: (series: { name: string | string[] }) =>
        Array.isArray(series.name) ? series.name[0] : series.name,
      getSubject,
      matchers: VALUE_MATCHERS,
      colorPaletteIndex: incBy1,
      getColorFromRule,
    };
  },
  categoricalBar: () => {
    return {
      defaultValueAccessor: 'category',
      forbiddenAccessors: /^category$/,
      getName: (series: { category: string }) => series.category,
      getSubject,
      matchers: VALUE_MATCHERS,
      colorPaletteIndex: always0,
      getColorFromRule: (rule) => {
        if (rule.colorPalette) {
          return rule.colorPalette as ColorPalette;
        }
        return { Default: getValidColor(rule.color ?? '') };
      },
    };
  },
  meterBar: () => {
    const getValueWithAccessor = (
      currentSeries: { [key: string]: unknown },
      valueAccessor: string,
    ) => {
      const accessor = getAccessor(valueAccessor);

      if (!accessor) {
        return null;
      }

      const value = get(currentSeries, accessor);
      return !isNil(value) ? value : null;
    };

    return {
      defaultValueAccessor: 'value',
      forbiddenAccessors: /^value$/,
      getName: (series: { value: Record<string, unknown> | number }) =>
        JSON.stringify(series.value),
      getSubject: function (
        rule: ColorRuleProps,
        currentSeries: {
          value: Record<string, unknown> | number;
          [key: string]: unknown;
        },
      ) {
        const valueAccessor =
          rule.valueAccessor ||
          (currentSeries['_chartValueAccessor'] as string);

        if (valueAccessor) {
          return getValueWithAccessor(currentSeries, valueAccessor);
        }

        return currentSeries.value;
      },
      matchers: VALUE_MATCHERS,
      colorPaletteIndex: incBy1,
      getColorFromRule,
    };
  },
  pieOrDonut: () => {
    return {
      defaultValueAccessor: 'value',
      forbiddenAccessors: /^(value|relativeValue)$/,
      getName: (series: { category: string }) => series.category,
      getSubject,
      matchers: VALUE_MATCHERS,
      colorPaletteIndex: incBy1,
      getColorFromRule,
    };
  },
  honeycomb: () => {
    return {
      defaultValueAccessor: 'value',
      forbiddenAccessors: /^value$/,
      getName: () => 'honeycomb',
      getSubject,
      matchers: VALUE_MATCHERS,
      colorPaletteIndex: always0,
      getColorFromRule,
    };
  },
  categoricalLegend: () => {
    return {
      defaultValueAccessor: 'valueOf',
      forbiddenAccessors: /(?:)/,
      getName: () => 'categoricalLegend',
      getSubject: (_rule, item) => item,
      matchers: VALUE_MATCHERS,
      colorPaletteIndex: always0,
      getColorFromRule,
    };
  },
  numericalLegend: () => {
    return {
      defaultValueAccessor: 'from',
      forbiddenAccessors: /(?:)/,
      getName: () => 'numericalLegend',
      getSubject: (_: ColorRuleProps, item: { from: number; to: number }) =>
        item,
      matchers: RANGE_MATCHERS,
      colorPaletteIndex: always0,
      getColorFromRule,
    };
  },
};
